/**
 * Panel Bootstrap - Inline Version with Dynamic Resource Loading (Minified)
 *
 * This file is for REFERENCE ONLY and documentation.
 * The actual bootstrap code should be INLINED in each panel's .hbs file.
 *
 * Why inline instead of external script?
 * ========================================
 * When a panel is embedded in an iframe, the browser cannot load this file
 * from /js/panel-bootstrap-inline.min.js because it needs the prefix
 * /neon/api/demo-integration/js/panel-bootstrap-inline.min.js
 *
 * But we need the bootstrap to SET that prefix in the first place!
 * This is a "chicken and egg" problem.
 *
 * Solution: Inline the bootstrap script directly in the HTML <head>,
 * so it loads synchronously with the HTML and has no external dependencies.
 *
 * Why dynamic resource loading?
 * =============================
 * The browser requests resources (script src="...", link href="...") IMMEDIATELY
 * when parsing HTML, BEFORE any JavaScript can run to fix the paths.
 *
 * Solution: The bootstrap dynamically creates and loads script/link elements
 * with the correct prefixed paths, ensuring resources are requested from the
 * right location whether standalone or embedded.
 *
 * Size: ~750 bytes minified (still negligible impact on HTML size)
 *
 * Usage in .hbs files:
 * ====================
 *
 * <head>
 *     <meta charset="UTF-8">
 *     <meta name="viewport" content="width=device-width, initial-scale=1.0">
 *     <title>Your Panel</title>
 *
 *     <!-- Panel Bootstrap (inline with dynamic resource loading) -->
 *     <script>
 * (function(w){'use strict';function e(){try{return w.self!==w.top}catch(e){return true}}const m=e(),p=m?'/neon/api/demo-integration':'';w.__PANEL_EMBED_PREFIX__=p;w.__PANEL_IS_EMBEDDED__=m;const l=document.createElement('link');l.rel='stylesheet';l.href=p+'/css/tailwind-panels.css';document.head.appendChild(l);const s=document.createElement('script');s.src=p+'/js/panel-api-helper.js';document.head.appendChild(s)})(window);
 *     </script>
 *
 *     <!-- NO MORE static <script src="..."> or <link href="..."> tags! -->
 *     <!-- Resources are loaded dynamically by the bootstrap -->
 * </head>
 *
 *
 * Readable Version (for understanding):
 * ======================================
 */

(function(window) {
    'use strict';

    // Detect if embedded in iframe
    function isEmbedded() {
        try {
            return window.self !== window.top;
        } catch (e) {
            // Cross-origin restriction means we're definitely embedded
            return true;
        }
    }

    // Calculate prefix
    const embedded = isEmbedded();
    const prefix = embedded ? '/neon/api/demo-integration' : '';

    // Set global variables for panel-api-helper.js to use
    window.__PANEL_EMBED_PREFIX__ = prefix;
    window.__PANEL_IS_EMBEDDED__ = embedded;

    // Dynamically load CSS with correct path
    const cssLink = document.createElement('link');
    cssLink.rel = 'stylesheet';
    cssLink.href = prefix + '/css/tailwind-panels.css';
    document.head.appendChild(cssLink);

    // Dynamically load JavaScript with correct path
    const jsScript = document.createElement('script');
    jsScript.src = prefix + '/js/panel-api-helper.js';
    document.head.appendChild(jsScript);
})(window);

/**
 * Minified Version (~750 bytes):
 * ===============================
 *
 * Copy this line and paste it in your panel's <head> inside a <script> tag:
 */

